const STOPWORDS = new Set(['and','the','for','with','of','or','in','to',
  'a','an','at','from','as','by','on','each','any','eg','ie','including',
  'without','per','type','area','procedure','procedures','other','same',
  'not','more','than','this','into','after','during','involving','using',
  'via','due','such','also']);

// Map Claude's procedure names to real CPT codes from the PDF
function findCodes(procedureNames, topPerProc = 3) {
  const results = [];
  const seen = new Set();

  for (const name of procedureNames) {
    const words = name.toLowerCase()
      .replace(/[(),;:\/-]/g, ' ')
      .split(/\s+/)
      .map(w => w.replace(/^[.,]+|[.,]+$/g, ''))
      .filter(w => w.length > 3 && !STOPWORDS.has(w));

    const scores = {};
    for (const word of words) {
      for (const code of (INDEX[word] || [])) {
        scores[code] = (scores[code] || 0) + 1;
      }
    }

    const ranked = Object.entries(scores)
      .sort((a, b) => b[1] - a[1])
      .slice(0, topPerProc);

    for (const [code, score] of ranked) {
      if (!seen.has(code) && CODES[code]) {
        seen.add(code);
        results.push({
          code,
          desc: CODES[code][0],
          area: CODES[code][1],
          confidence: score >= 2 ? 'high' : 'medium'
        });
      }
    }
  }
  return results;
}

export default async function handler(req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  const { transcript, specialty = 'plastic-surgery', year = '4' } = req.body;
  if (!transcript) return res.status(400).json({ error: 'No transcript provided' });

  // TODO: When adding new specialties, load specialty-specific CODES/INDEX here
  // e.g. const { CODES, INDEX } = DB[specialty] || DB['plastic-surgery'];
  // For now all specialties use the Plastic Surgery PDF until others are uploaded

  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) return res.status(500).json({ error: 'API key not configured' });

  try {
    // Ask Claude for procedure names only — tiny prompt ~$0.001 per call
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 400,
        system: `You are a medical assistant for a Plastic Surgery residency at Larkin Community Hospital, Hialeah FL.
Extract case details from the resident's spoken description.
Available attendings: Dr. Smith, Dr. Johnson, Dr. Williams, Dr. Brown.
Available sites: Larkin Community Hospital, Larkin Palm Springs, Affiliated Site.

Return ONLY valid JSON, no markdown:
{
  "role": "Surgeon" | "Assistant" | "Teaching Assistant" | "Observer",
  "patientType": "Adult" | "Pediatric",
  "caseYear": 1-6,
  "attending": "Dr. Smith" | "Dr. Johnson" | "Dr. Williams" | "Dr. Brown" | null,
  "site": "Larkin Community Hospital" | "Larkin Palm Springs" | "Affiliated Site" | null,
  "notes": "brief clinical notes",
  "procedures": ["specific procedure name 1", "specific procedure name 2"]
}
List each procedure performed separately and specifically.
Examples: "breast augmentation with implant", "peri-implant capsulectomy complete", "abdominoplasty", "rhinoplasty primary", "blepharoplasty upper eyelid", "removal of intact breast implant"`,
        messages: [{ role: 'user', content: `Extract case details: "${transcript}"` }]
      })
    });

    if (!response.ok) {
      console.error('Anthropic error:', await response.text());
      return res.status(502).json({ error: 'AI service error' });
    }

    const aiData = await response.json();
    const rawText = aiData.content.filter(b => b.type === 'text').map(b => b.text).join('');
    const parsed = JSON.parse(rawText.replace(/```json|```/g, '').trim());

    // Map procedure names → CPT codes using local index
    // Only codes from your ACGME PDF can ever appear here
    const suggestedCodes = findCodes(parsed.procedures || []);

    return res.status(200).json({
      role: parsed.role || 'Surgeon',
      patientType: parsed.patientType || 'Adult',
      caseYear: parsed.caseYear || 4,
      attending: parsed.attending || null,
      site: parsed.site || null,
      notes: parsed.notes || '',
      suggestedCodes
    });

  } catch (err) {
    console.error('Error:', err);
    return res.status(500).json({ error: 'Failed to parse case', detail: err.message });
  }
}
